var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"땅 밑에 이딴 시설은 왜 이렇게 많이 만든 거야?","JPN":"なんでこんなたくさんの施設を地下に作ったんだか。","ENG":"Why did they build so many underground structures?","TWN":"為什麼在地底下搞這麼多東西？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"지하를 무슨 비밀 통로처럼 잔뜩 만들어놨네.","JPN":"まるで、何かの秘密通路みたい。","ENG":"It's like the whole place is one big secret passageway.","TWN":"地下弄得像是秘密通道一樣。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"형제님! 지하는 음기가 강한 곳 중 하나입니다.","JPN":"ブラザー！　地下は陰気が強い場所の1つです。","ENG":"Brother Ludwig! The underground is one of the most evil spiritually charged places.","TWN":"地下是陰氣最重的地方之一！"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"이런 곳에 시설을 지으면 자연스레 악령이 꼬이게 돼요.","JPN":"このような場所に施設を建てると、自然に悪霊が集うことになりますよ。","ENG":"Building facilities here naturally attracts evil spirits.","TWN":"在這種地方弄東弄西，自然會招來惡靈。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"우리 수도원을 통해 꾸준히 제령 의식을 치르는 것을 추천해 드립니다.","JPN":"修道院を通じて持続的に除霊儀式を行うことをおすすめします。","ENG":"I highly recommend scheduling regular exorcism rituals through our monastery.","TWN":"建議你透過我們的修道院定期進行驅魔儀式。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"하아, 영지에 이렇게 문제가 많았다니.","JPN":"はあ、領地にこれほど多くの問題があったとは。","ENG":"*Sigh* I didn't realize my estate had so many problems.","TWN":"哀，領地裡竟然有這麼多問題。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"모르는 건 당연합니다. 형제님 같은 분들을 위해 제가 오지 않았습니까?","JPN":"知らなくて当然です。ブラザーのような方々のために、私が来たではありませんか。","ENG":"That's understandable. That's why I'm here to help, after all.","TWN":"不知道是正常的，所以才需要我不是嗎？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"물론 유료지만.","JPN":"もちろんお金はいただきますが。","ENG":"Of course, it's not free.","TWN":"當然是要收錢的囉。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"잠시만요.","JPN":"待ってください。","ENG":"Hold on a moment.","TWN":"請稍等。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"뭘 하고 있는 건가?","JPN":"何をしているのかね？","ENG":"What are you doing?","TWN":"你在做什麼呢？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"주술진을 그리고 있습니다.","JPN":"呪術陣を描いています。","ENG":"Setting up a warding circle.","TWN":"正在繪製咒術陣。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"일종의 경보기 역할을 하죠.","JPN":"一種の警報器のようなものですよ。","ENG":"It works like a security alarm.","TWN":"它可以起到一種警報器的作用。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"수녀들은 그런 것도 할 줄 아는 건가?","JPN":"シスターというのはそんなこともできるのか？","ENG":"Can nuns do things like that?","TWN":"修女也會做那種事嗎？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"신비롭군. 원리가 뭐지?","JPN":"神秘的だな。原理は何だ？","ENG":"Fascinating. How does it work?","TWN":"真神奇啊，這是什麼原理？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"아하하, 수도원의 기밀이라서요.","JPN":"あはは、修道院の機密ですので。","ENG":"Ahaha, that's a secret of our monastery.","TWN":"啊哈哈，這是修道院的機密。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"기타 궁금한 사항은 발렌티누스 수도원으로 문의 부탁드려요.","JPN":"その他の質問はバレンチヌス修道院までお問い合わせください。","ENG":"If you have further questions, please contact the Valentinus Monastery.","TWN":"其他疑問請諮詢聖華倫修道院。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"흠……냄새가 이쪽으로 이어지는 것 같은데.","JPN":"ふーん……匂いがこっちに繋がってるみたいだけど。","ENG":"Hmm... The scent seems to be leading this way.","TWN":"嗯……味道好像是從這邊傳來的。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"그러고 보니 아까도 역한 냄새를 맡았다고 했지.","JPN":"そういえば、さっきも酷い匂いがすると言っていたな。","ENG":"Now that I think about it, you mentioned smelling something foul earlier.","TWN":"這麼說來，你剛才也說聞到了噁心的味道。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"신기하군. 그게 자네의 능력인가?","JPN":"気になっていたのだが、それが君の能力なのか？","ENG":"Interesting. Is that your ability?","TWN":"真是神奇。這就是你的能力嗎？"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"능력이라기엔 좀 거창하네요.","JPN":"能力なんて大げさな。","ENG":"Calling it an ability is a bit much.","TWN":"說是能力未免有些誇張了。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"<color=#ffd34c>병</color>이 저에게 준 후유증이라고 생각해 주세요.","JPN":"<color=#ffd34c>病気</color>が私に与えてくれた後遺症と思ってください。","ENG":"Think of it as an aftereffect of my <color=#ffd34c>sickness</color>.","TWN":"就當作是<color=#ffd34c>疾病</color>給我留下的後遺症吧。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LUDWIG_MOONLIGHT_NPC_NULL","text":{"KOREA":"병이라…… 흥미롭군.","JPN":"病気か……興味深い。","ENG":"A sickness...? How interesting.","TWN":"疾病嗎……很有趣呢。"},"stage":{"bg":"UNDER","slots":{"L":null,"C":{"char_id":"LUDWIG_MOONLIGHT_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LUCIA_MOONLIGHT_NULL_NULL","text":{"KOREA":"음? 여기 문이 있는데요.","JPN":"うん？　ここに扉がありますね。","ENG":"Oh? There's a door here.","TWN":"嗯？這裡有門呢。"},"stage":{"bg":"CORRIDOR_08","slots":{"L":null,"C":{"char_id":"LUCIA_MOONLIGHT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};